'use client';

import Link from 'next/link';
import { useMemo, useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import {
  AlertTriangle,
  CheckCircle2,
  Clock3,
  FileSpreadsheet,
  Loader2,
  RefreshCw,
  Search,
  TriangleAlert,
  XCircle,
} from 'lucide-react';

type BatchStatus = 'UPLOADED' | 'VALIDATED' | 'IMPORTED' | 'FAILED';

type ImportBatch = {
  id: string;
  uploadedFileId: string | null;
  sourceFilename: string;
  templateVersion: string | null;
  status: BatchStatus;
  totalRows: number;
  validRows: number;
  invalidRows: number;
  warningRows: number;
  createdAt: string;
  importedAt: string | null;
  billingCycle: {
    id: string;
    year: number;
    month: number;
    status: string;
    building: {
      id: string;
      name: string;
    } | null;
  } | null;
};

const STATUS_OPTIONS: Array<BatchStatus | 'ALL'> = ['ALL', 'UPLOADED', 'VALIDATED', 'IMPORTED', 'FAILED'];

function formatDate(value: string | null) {
  if (!value) return '—';
  return new Date(value).toLocaleString('th-TH', {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function monthLabel(month: number, year: number) {
  return `${String(month).padStart(2, '0')}/${year}`;
}

function statusBadge(status: BatchStatus) {
  if (status === 'IMPORTED') return 'inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-semibold bg-tertiary-container text-on-tertiary-container';
  if (status === 'FAILED') return 'inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-semibold bg-error-container text-on-error-container';
  if (status === 'VALIDATED') return 'inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-semibold bg-amber-50 text-amber-700 border border-amber-200';
  return 'inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-semibold bg-surface-container text-on-surface-variant border border-outline-variant';
}

export default function BillingBatchesPage() {
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState<BatchStatus | 'ALL'>('ALL');
  const _queryClient = useQueryClient();

  const { data: batchesData, isLoading: loading, error, refetch } = useQuery<{ success: boolean; data: { batches: ImportBatch[] } }>({
    queryKey: ['billing-batches', status],
    queryFn: async () => {
      const params = new URLSearchParams({ pageSize: '100' });
      if (status !== 'ALL') params.set('status', status);
      const response = await fetch(`/api/billing/import/batches?${params.toString()}`, {
        cache: 'no-store',
      });
      const json = await response.json();
      if (!response.ok || !json.success) {
        throw new Error(json.error?.message ?? 'ไม่สามารถโหลดแบทช์นำเข้า');
      }
      return json;
    },
  });

  const batches: ImportBatch[] = batchesData?.data?.batches ?? [];

  const filtered = useMemo(() => {
    const needle = search.trim().toLowerCase();
    if (!needle) return batches;
    return batches.filter((batch) => {
      const cycle = batch.billingCycle ? monthLabel(batch.billingCycle.month, batch.billingCycle.year) : '';
      return (
        batch.sourceFilename.toLowerCase().includes(needle) ||
        batch.id.toLowerCase().includes(needle) ||
        cycle.toLowerCase().includes(needle) ||
        (batch.billingCycle?.building?.name ?? '').toLowerCase().includes(needle)
      );
    });
  }, [batches, search]);

  const stats = useMemo(() => {
    return {
      total: batches.length,
      imported: batches.filter((batch) => batch.status === 'IMPORTED').length,
      needsReview: batches.filter((batch) => batch.warningRows > 0 || batch.invalidRows > 0).length,
      latestImportedAt: [...batches]
        .filter((batch) => batch.importedAt)
        .sort((a, b) => (new Date(b.importedAt || 0).getTime() - new Date(a.importedAt || 0).getTime()))[0]
        ?.importedAt ?? null,
    };
  }, [batches]);

  return (
    <main className="space-y-6">
      <div className="relative overflow-hidden rounded-xl bg-gradient-to-br from-primary-container to-primary px-6 py-5 shadow-lg">
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top_right,_rgba(255,255,255,0.15),_transparent_60%)]" />
        <div className="relative flex items-center justify-between">
          <div>
            <h1 className="text-base font-semibold text-on-primary">แบทช์นำเข้าการเรียกเก็บ</h1>
            <p className="text-xs text-on-primary/80 mt-0.5">
              ทุกเวิร์กบุ๊กจะถูกจัดเตรียมที่นี่ก่อน ตรวจสอบทีละแถว แล้วจึงยืนยันเป็นบันทึกการเรียกเก็บจริง
            </p>
          </div>
          <div className="flex items-center gap-3">
            <Link href="/admin/billing/import" className="inline-flex items-center gap-2 rounded-lg bg-white/20 px-4 py-2 text-sm font-semibold text-on-primary shadow-sm transition-colors hover:bg-white/30">
              นำเข้าใหม่
            </Link>
            <button onClick={() => void refetch()} className="inline-flex items-center gap-2 rounded-lg border border-white/30 bg-white/20 px-4 py-2 text-sm font-medium text-on-primary shadow-sm transition-colors hover:bg-white/30" disabled={loading}>
              <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
              รีเฟรช
            </button>
          </div>
        </div>
      </div>

      {error ? (
        <div className="flex items-center gap-2 rounded-lg border border-error-container bg-error-container/20 px-4 py-3 text-sm font-medium text-on-error-container">
          <AlertTriangle className="h-4 w-4 shrink-0" />
          {error instanceof Error ? error.message : String(error)}
        </div>
      ) : null}

      <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 p-5">
          <div className="text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">แบทช์ทั้งหมด</div>
          <div className="text-2xl font-extrabold text-primary">{stats.total}</div>
        </div>
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 p-5">
          <div className="text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">นำเข้าแล้ว</div>
          <div className="text-2xl font-extrabold text-primary text-emerald-600">{stats.imported}</div>
        </div>
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 p-5">
          <div className="text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">ต้องตรวจสอบ</div>
          <div className="text-2xl font-extrabold text-primary text-amber-600">{stats.needsReview}</div>
        </div>
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 p-5">
          <div className="text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">นำเข้าล่าสุด</div>
          <div className="mt-2 text-sm font-medium text-on-surface">{formatDate(stats.latestImportedAt)}</div>
        </div>
      </section>

      <section className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 overflow-hidden">
        <div className="px-5 py-4 border-b border-outline-variant">
          <div className="text-sm font-semibold text-primary">คลังแบทช์</div>
          <div className="flex items-center gap-2">
            <label className="relative">
              <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-on-surface-variant" />
              <input
                value={search}
                onChange={(event) => setSearch(event.target.value)}
                placeholder="ค้นหาแบทช์ ชื่อไฟล์ รอบ..."
                className="w-full rounded-xl border border-outline bg-surface-container-lowest pl-9 pr-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20"
              />
            </label>
            <select
              value={status}
              onChange={(event) => setStatus(event.target.value as BatchStatus | 'ALL')}
              className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20"
            >
              {STATUS_OPTIONS.map((option) => (
                <option key={option} value={option}>
                  {option === 'ALL' ? 'ทุกสถานะ' : option}
                </option>
              ))}
            </select>
          </div>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-16 text-on-surface-variant">
            <Loader2 className="mr-2 h-5 w-5 animate-spin" />
            กำลังโหลดแบทช์นำเข้า...
          </div>
        ) : filtered.length === 0 ? (
          <div className="flex flex-col items-center gap-3 py-16 text-center">
            <FileSpreadsheet className="h-10 w-10 text-on-surface-variant" />
            <div>
              <div className="font-semibold text-on-surface">ไม่พบแบทช์นำเข้า</div>
              <div className="text-sm text-on-surface-variant">อัปโหลดเวิร์กบุ๊กแรกเพื่อเริ่มจัดเตรียมการเรียกเก็บรายเดือน</div>
            </div>
          </div>
        ) : (
          <div className="overflow-auto">
            <table className="w-full text-sm text-left">
              <thead>
                <tr className="bg-surface-container">
                  <th className="px-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">แบทช์</th>
                  <th className="px-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">รอบ</th>
                  <th className="px-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">สถานะ</th>
                  <th className="px-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">แถว</th>
                  <th className="px-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">เตือน / ข้อผิดพลาด</th>
                  <th className="px-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">นำเข้าเมื่อ</th>
                  <th />
                </tr>
              </thead>
              <tbody className="divide-y divide-outline-variant/10">
                {filtered.map((batch) => (
                  <tr key={batch.id} className="hover:bg-surface-container-lowest transition-colors">
                    <td>
                      <div className="font-medium text-on-surface">{batch.sourceFilename}</div>
                      <div className="mt-1 font-mono text-[11px] text-on-surface-variant">{batch.id}</div>
                    </td>
                    <td>
                      {batch.billingCycle ? (
                        <div>
                          <div className="font-semibold text-on-surface">
                            {monthLabel(batch.billingCycle.month, batch.billingCycle.year)}
                          </div>
                          <div className="text-xs text-on-surface-variant">
                            {batch.billingCycle.building?.name ?? 'Main building'}
                          </div>
                        </div>
                      ) : (
                        '—'
                      )}
                    </td>
                    <td>
                      <span className={statusBadge(batch.status)}>{batch.status}</span>
                    </td>
                    <td>
                      <div className="font-semibold text-on-surface">{batch.totalRows}</div>
                      <div className="text-xs text-on-surface-variant">{batch.validRows} ready rows</div>
                    </td>
                    <td>
                      <div className="flex flex-wrap gap-2">
                        <span className="inline-flex items-center gap-1 rounded-full border border-amber-200 bg-amber-50 px-2.5 py-0.5 text-xs font-medium text-amber-700">
                          <TriangleAlert className="h-3.5 w-3.5" />
                          {batch.warningRows}
                        </span>
                        <span className="inline-flex items-center gap-1 rounded-full border border-red-200 bg-red-50 px-2.5 py-0.5 text-xs font-medium text-red-600">
                          <XCircle className="h-3.5 w-3.5" />
                          {batch.invalidRows}
                        </span>
                      </div>
                    </td>
                    <td>
                      <div className="text-sm text-on-surface">{formatDate(batch.importedAt)}</div>
                      <div className="mt-1 text-xs text-on-surface-variant">สร้างเมื่อ {formatDate(batch.createdAt)}</div>
                    </td>
                    <td>
                      <div className="flex items-center justify-end gap-2">
                        {batch.billingCycle ? (
                          <Link href={`/admin/billing/${batch.billingCycle.id}`} className="inline-flex items-center gap-2 rounded-lg border border-outline bg-surface-container-lowest px-3 py-1.5 text-xs font-medium text-on-surface shadow-sm transition-colors hover:bg-surface-container text-xs">
                            รอบ
                          </Link>
                        ) : null}
                        <Link href={`/admin/billing/batches/${batch.id}`} className="inline-flex items-center gap-2 rounded-lg border border-outline bg-surface-container-lowest px-3 py-1.5 text-xs font-medium text-on-surface shadow-sm transition-colors hover:bg-surface-container text-xs">
                          รายละเอียด
                        </Link>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>

      <section className="grid gap-4 lg:grid-cols-3">
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 p-5">
          <div className="mb-3 flex items-center gap-2 text-on-surface">
            <Clock3 className="h-4 w-4 text-primary" />
            <span className="font-semibold">จัดเตรียมก่อนยืนยัน</span>
          </div>
          <p className="text-sm text-on-surface-variant">
            เวิร์กบุ๊กที่อัปโหลดจะไปที่การจัดเตรียมก่อน พนักงานสามารถตรวจสอบยอดรวมและการจับคู่ห้องก่อนที่จะมีผลกับบันทึกการเรียกเก็บจริง
          </p>
        </div>
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 p-5">
          <div className="mb-3 flex items-center gap-2 text-on-surface">
            <TriangleAlert className="h-4 w-4 text-amber-500" />
            <span className="font-semibold">การเตือนยังคงแสดง</span>
          </div>
          <p className="text-sm text-on-surface-variant">
            ความไม่ตรงกันของ TotalAmount และปัญหาการตรวจสอบยังคงอยู่กับแบทช์ เพื่อให้ร่องรอยการตรวจสอบไม่หายไปหลังจากการนำเข้ารายเดือนเสร็จสิ้น
          </p>
        </div>
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 p-5">
          <div className="mb-3 flex items-center gap-2 text-on-surface">
            <CheckCircle2 className="h-4 w-4 text-emerald-500" />
            <span className="font-semibold">ลิงก์การนำเข้าสามารถตรวจสอบย้อนได้</span>
          </div>
          <p className="text-sm text-on-surface-variant">
            ทุกแบทช์ที่ยืนยันจะเก็บการอ้างอิงถึงบันทึกการเรียกเก็บที่สร้าง เพื่อให้ฝ่ายการเงินสามารถตรวจสอบได้ว่าแถวใดในเวิร์กบุ๊กสร้างบิลห้องใด
          </p>
        </div>
      </section>
    </main>
  );
}

'use client';

import React, { _useCallback, useMemo, useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import {
  FileText,
  Search,
  Plus,
  X,
  ChevronRight,
  FileSignature,
  AlertCircle,
  CheckCircle2,
  Clock,
  XCircle,
  Pencil,
  RefreshCw,
} from 'lucide-react';

// ─── Types ───────────────────────────────────────────────────────────────────

type ContractStatus = 'ACTIVE' | 'EXPIRED' | 'TERMINATED';

interface ContractRecord {
  id: string;
  roomNo: string;
  primaryTenantId: string;
  startDate: string;
  endDate: string;
  rentAmount: number;
  depositAmount: number;
  status: ContractStatus;
  terminationDate: string | null;
  terminationReason: string | null;
  createdAt: string;
  updatedAt: string;
  room?: { roomNo: string };
  primaryTenant?: {
    id: string;
    firstName: string;
    lastName: string;
    fullName: string;
    phone: string;
  };
}

interface ContractListResponse {
  data: ContractRecord[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

interface RoomOption {
  roomNo: string;
  floorNo: number;
  roomStatus: string;
  defaultRentAmount: number;
}

interface TenantOption {
  id: string;
  firstName: string;
  lastName: string;
  fullName: string;
  phone: string;
}

type PanelMode = 'none' | 'new' | 'edit';

const EMPTY_NEW_FORM = {
  roomId: '',
  primaryTenantId: '',
  startDate: '',
  endDate: '',
  rentAmount: '',
  depositAmount: '',
  notes: '',
};

const EMPTY_EDIT_FORM = {
  startDate: '',
  endDate: '',
  rentAmount: '',
  depositAmount: '',
  status: 'ACTIVE' as ContractStatus,
};

// ─── Helpers ─────────────────────────────────────────────────────────────────

function fmtDate(d: string | Date | null | undefined): string {
  if (!d) return '—';
  const date = typeof d === 'string' ? new Date(d) : d;
  return date.toLocaleDateString('th-TH', { day: '2-digit', month: 'short', year: 'numeric' });
}

function fmtMoney(n: number): string {
  return n.toLocaleString('th-TH', { minimumFractionDigits: 0 }) + ' ฿';
}

function daysUntil(dateStr: string): number {
  const end = new Date(dateStr);
  const now = new Date();
  now.setHours(0, 0, 0, 0);
  end.setHours(0, 0, 0, 0);
  return Math.round((end.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
}

function resolveDisplayStatus(contract: ContractRecord): 'ACTIVE' | 'EXPIRED' | 'TERMINATED' | 'EXPIRING_SOON' {
  if (contract.status === 'TERMINATED') return 'TERMINATED';
  if (contract.status === 'EXPIRED') return 'EXPIRED';
  const days = daysUntil(contract.endDate);
  if (days <= 30 && days >= 0) return 'EXPIRING_SOON';
  return 'ACTIVE';
}

// ─── Status Badge ─────────────────────────────────────────────────────────────

function StatusBadge({ status }: { status: ReturnType<typeof resolveDisplayStatus> }) {
  const cfg = {
    ACTIVE:        { label: 'ใช้งาน',         cls: 'bg-emerald-100 text-emerald-800 border border-emerald-200',  Icon: CheckCircle2 },
    EXPIRING_SOON: { label: 'ใกล้หมดอายุ',  cls: 'bg-amber-100 text-amber-800 border border-amber-200',       Icon: Clock },
    EXPIRED:       { label: 'หมดอายุ',        cls: 'bg-red-100 text-red-700 border border-red-200',             Icon: XCircle },
    TERMINATED:    { label: 'ยกเลิก',     cls: 'bg-surface-container text-on-surface border border-outline-variant',       Icon: XCircle },
  }[status];

  return (
    <span className={`inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-semibold ${cfg.cls}`}>
      <cfg.Icon size={10} />
      {cfg.label}
    </span>
  );
}

// ─── KPI Card ─────────────────────────────────────────────────────────────────

function KpiCard({
  label,
  value,
  sub,
  color,
  icon: Icon,
}: {
  label: string;
  value: number | string;
  sub?: string;
  color: string;
  icon: React.ElementType;
}) {
  return (
    <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 flex items-center gap-4 py-4 px-5">
      <div className={`flex h-11 w-11 shrink-0 items-center justify-center rounded-xl ${color}`}>
        <Icon size={20} className="text-white" strokeWidth={2} />
      </div>
      <div className="min-w-0">
        <div className="text-[11px] font-medium uppercase tracking-wider text-on-surface-variant">{label}</div>
        <div className="text-2xl font-bold text-on-surface leading-tight">{value}</div>
        {sub && <div className="text-[11px] text-on-surface-variant mt-0.5">{sub}</div>}
      </div>
    </div>
  );
}

// ─── Main Page ────────────────────────────────────────────────────────────────

export default function AdminContractsPage() {
  const queryClient = useQueryClient();

  // Filter / search state
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('');
  const [page, setPage] = useState(1);

  // Panel state
  const [panelMode, setPanelMode] = useState<PanelMode>('none');
  const [selectedContract, setSelectedContract] = useState<ContractRecord | null>(null);

  // Form state — new contract
  const [newForm, setNewForm] = useState({ ...EMPTY_NEW_FORM });
  const [newSaving, setNewSaving] = useState(false);
  const [newError, setNewError] = useState<string | null>(null);

  // Form state — edit contract
  const [editForm, setEditForm] = useState({ ...EMPTY_EDIT_FORM });
  const [editSaving, setEditSaving] = useState(false);
  const [editError, setEditError] = useState<string | null>(null);
  const [editSuccess, setEditSuccess] = useState<string | null>(null);

  // ── Contracts query ────────────────────────────────────────────────────────

  const { data: contractsData, isLoading: contractsLoading, error: contractsError, refetch: refetchContracts } = useQuery({
    queryKey: ['contracts', page, filterStatus],
    queryFn: async () => {
      const params = new URLSearchParams({
        page: String(page),
        pageSize: '50',
      });
      if (filterStatus && filterStatus !== 'EXPIRING_SOON') {
        params.set('status', filterStatus);
      }
      const res = await fetch(`/api/contracts?${params}`);
      if (!res.ok) throw new Error(`ไม่สำเร็จ: รหัส ${res.status}`);
      const json: { success: boolean; data: ContractListResponse } = await res.json();
      if (!json.success) throw new Error('API ส่งคืนข้อผิดพลาด');
      return json.data;
    },
  });

  const contracts = contractsData?.data ?? [];
  const total = contractsData?.total ?? 0;
  const loading = contractsLoading;
  const error = contractsError?.message ?? null;

  // ── Rooms query (for new contract form) ────────────────────────────────────

  const { data: roomsData } = useQuery({
    queryKey: ['rooms-vacant'],
    queryFn: async () => {
      const res = await fetch('/api/rooms?pageSize=300&roomStatus=VACANT');
      if (!res.ok) return [];
      const json = await res.json();
      return json.success ? (json.data.data ?? []) : [];
    },
    enabled: panelMode === 'new',
  });

  const rooms: RoomOption[] = roomsData ?? [];

  // ── Tenants query (per room) ────────────────────────────────────────────────

  const { data: tenantsData, isLoading: tenantsLoading } = useQuery({
    queryKey: ['room-tenants', newForm.roomId],
    queryFn: async () => {
      if (!newForm.roomId) return [];
      const res = await fetch(`/api/rooms/${encodeURIComponent(newForm.roomId)}/tenants`);
      if (!res.ok) return [];
      const json = await res.json();
      if (!json.success) return [];
      const tenants: TenantOption[] = (json.data as TenantOption[]).map((t) => ({
        id: t.id,
        firstName: t.firstName,
        lastName: t.lastName,
        fullName: t.fullName ?? `${t.firstName} ${t.lastName}`,
        phone: t.phone,
      }));
      return tenants;
    },
    enabled: !!newForm.roomId,
  });

  const roomTenantsMap: Record<string, TenantOption[]> = {};
  if (newForm.roomId && tenantsData) {
    roomTenantsMap[newForm.roomId] = tenantsData;
  }

  // ── Derived / computed ──────────────────────────────────────────────────────

  const filteredContracts = useMemo(() => {
    let list = contracts;

    // Client-side search (room number / tenant name)
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter(
        (c) =>
          c.roomNo.toLowerCase().includes(q) ||
          (c.primaryTenant?.fullName ?? '').toLowerCase().includes(q)
      );
    }

    // Client-side "Expiring Soon" filter (server doesn't expose it directly)
    if (filterStatus === 'EXPIRING_SOON') {
      list = list.filter((c) => {
        const days = daysUntil(c.endDate);
        return c.status === 'ACTIVE' && days >= 0 && days <= 30;
      });
    }

    return list;
  }, [contracts, search, filterStatus]);

  const kpis = useMemo(() => {
    const all = contracts;
    const active = all.filter((c) => c.status === 'ACTIVE');
    const expiringSoon = active.filter((c) => {
      const d = daysUntil(c.endDate);
      return d >= 0 && d <= 30;
    });
    const expired = all.filter((c) => c.status === 'EXPIRED');
    return {
      total: total,
      active: active.length,
      expiringSoon: expiringSoon.length,
      expired: expired.length,
    };
  }, [contracts, total]);

  // ── Handlers ────────────────────────────────────────────────────────────────

  function openNew() {
    setNewForm({ ...EMPTY_NEW_FORM });
    setNewError(null);
    setPanelMode('new');
    setSelectedContract(null);
  }

  function openEdit(c: ContractRecord) {
    setSelectedContract(c);
    setEditForm({
      startDate: c.startDate.slice(0, 10),
      endDate: c.endDate.slice(0, 10),
      rentAmount: String(c.rentAmount),
      depositAmount: String(c.depositAmount),
      status: c.status,
    });
    setEditError(null);
    setEditSuccess(null);
    setPanelMode('edit');
  }

  function closePanel() {
    setPanelMode('none');
    setSelectedContract(null);
    setNewError(null);
    setEditError(null);
    setEditSuccess(null);
  }

  async function handleNewSubmit(e: React.FormEvent) {
    e.preventDefault();
    setNewSaving(true);
    setNewError(null);
    try {
      const body = {
        roomId: newForm.roomId,
        primaryTenantId: newForm.primaryTenantId,
        startDate: newForm.startDate,
        endDate: newForm.endDate,
        rentAmount: parseFloat(newForm.rentAmount),
        depositAmount: newForm.depositAmount ? parseFloat(newForm.depositAmount) : 0,
      };
      const res = await fetch('/api/contracts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      const json = await res.json();
      if (!res.ok || !json.success) {
        throw new Error(json.message ?? json.error ?? `ไม่สำเร็จ: รหัส ${res.status}`);
      }
      closePanel();
      void queryClient.invalidateQueries({ queryKey: ['contracts'] });
    } catch (err) {
      setNewError(err instanceof Error ? err.message : 'ไม่สามารถสร้างสัญญา');
    } finally {
      setNewSaving(false);
    }
  }

  async function handleEditSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!selectedContract) return;
    setEditSaving(true);
    setEditError(null);
    setEditSuccess(null);
    try {
      const body = {
        startDate: editForm.startDate || undefined,
        endDate: editForm.endDate || undefined,
        rentAmount: editForm.rentAmount ? parseFloat(editForm.rentAmount) : undefined,
        depositAmount: editForm.depositAmount !== '' ? parseFloat(editForm.depositAmount) : undefined,
      };
      const res = await fetch(`/api/contracts/${selectedContract.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (res.status === 404) {
        throw new Error('ปลายทางอัปเดตยังไม่พร้อมใช้งาน กรุณาติดต่อผู้พัฒนา');
      }
      const json = await res.json();
      if (!res.ok || !json.success) {
        throw new Error(json.message ?? json.error ?? `ไม่สำเร็จ: รหัส ${res.status}`);
      }
      setEditSuccess('อัปเดตสัญญาเรียบร้อยแล้ว');
      void queryClient.invalidateQueries({ queryKey: ['contracts'] });
    } catch (err) {
      setEditError(err instanceof Error ? err.message : 'ไม่สามารถอัปเดตสัญญา');
    } finally {
      setEditSaving(false);
    }
  }

  // ── Render ──────────────────────────────────────────────────────────────────

  const selectedTenants = newForm.roomId ? (roomTenantsMap[newForm.roomId] ?? []) : [];

  return (
    <div className="flex min-h-0 flex-1">
      {/* ── Main content ─────────────────────────────────────────── */}
      <main
        className={`space-y-6 flex-1 min-w-0 transition-all duration-200 ${
          panelMode !== 'none' ? 'mr-0 xl:mr-[420px]' : ''
        }`}
      >
        {/* Header */}
        <div className="relative overflow-hidden rounded-xl bg-gradient-to-br from-primary-container to-primary px-6 py-5 shadow-lg">
          <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top_right,_rgba(255,255,255,0.15),_transparent_60%)]" />
          <div className="relative flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-white/20 ring-1 ring-white/30">
                <FileSignature size={20} className="text-white" strokeWidth={2} />
              </div>
              <div>
                <h1 className="text-base font-semibold text-on-primary">สัญญาเช่า</h1>
                <p className="text-xs text-on-primary/80 mt-0.5">จัดการสัญญาเช่าสำหรับทุกห้องที่มีผู้เช่า</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <button
                className="inline-flex items-center gap-1.5 rounded-lg border border-white/30 bg-white/20 px-4 py-2 text-sm font-medium text-on-primary shadow-sm transition-colors hover:bg-white/30"
                onClick={() => void refetchContracts()}
                title="Refresh"
              >
                <RefreshCw size={13} />
                รีเฟรช
              </button>
              <button
                className="inline-flex items-center gap-1.5 rounded-lg bg-white/20 px-4 py-2 text-sm font-semibold text-on-primary shadow-sm transition-colors hover:bg-white/30"
                onClick={openNew}
              >
                <Plus size={14} strokeWidth={2.5} />
                สร้างสัญญาใหม่
              </button>
            </div>
          </div>
        </div>

        {/* KPI Row */}
        <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4 mb-1">
          <KpiCard
            label="สัญญาทั้งหมด"
            value={kpis.total}
            sub="ทั้งหมด"
            color="bg-indigo-500"
            icon={FileText}
          />
          <KpiCard
            label="ใช้งาน"
            value={kpis.active}
            sub="กำลังใช้งาน"
            color="bg-emerald-500"
            icon={CheckCircle2}
          />
          <KpiCard
            label="ใกล้หมดอายุ"
            value={kpis.expiringSoon}
            sub="ภายใน 30 วัน"
            color="bg-amber-500"
            icon={Clock}
          />
          <KpiCard
            label="หมดอายุ"
            value={kpis.expired}
            sub="เกินวันสิ้นสุด"
            color="bg-red-400"
            icon={XCircle}
          />
        </div>

        {/* Toolbar */}
        <div className="flex flex-wrap items-center gap-2 mb-4 mt-4">
          <div className="relative flex-1 min-w-[200px]">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-on-surface-variant" />
            <input
              className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20 pl-8 w-full"
              placeholder="ค้นหาหมายเลขห้องหรือชื่อผู้เช่า..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <select
            className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20"
            value={filterStatus}
            onChange={(e) => {
              setFilterStatus(e.target.value);
              setPage(1);
            }}
          >
            <option value="">ทุกสถานะ</option>
            <option value="ACTIVE">ใช้งาน</option>
            <option value="EXPIRING_SOON">ใกล้หมดอายุ</option>
            <option value="EXPIRED">หมดอายุ</option>
            <option value="TERMINATED">ยกเลิก</option>
          </select>
        </div>

        {/* Error banner */}
        {error && (
          <div className="mb-4 flex items-center gap-2 rounded-lg border border-error-container bg-error-container/20 px-4 py-3 text-sm font-medium text-on-error-container">
            <AlertCircle size={15} />
            {error}
          </div>
        )}

        {/* Table */}
        <div className="bg-surface-container-lowest rounded-xl border border-outline-variant/10 overflow-hidden p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead>
                <tr className="bg-surface-container">
                  <th className="pl-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">หมายเลขห้อง</th>
                  <th className="py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">ชื่อผู้เช่า</th>
                  <th className="py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">วันที่เริ่ม</th>
                  <th className="py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">วันที่สิ้นสุด</th>
                  <th className="py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">ค่าเช่ารายเดือน</th>
                  <th className="py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">เงินมัดจำ</th>
                  <th className="py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant">สถานะ</th>
                  <th className="pr-4 py-3 text-[10px] font-bold uppercase tracking-widest text-on-surface-variant text-right">การดำเนินการ</th>
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  Array.from({ length: 5 }).map((_, i) => (
                    <tr key={i}>
                      {Array.from({ length: 8 }).map((__, j) => (
                        <td key={j}>
                          <div className="h-4 rounded bg-surface-container animate-pulse" style={{ width: `${70 + (i * 13 + j * 17) % 25}%` }} />
                        </td>
                      ))}
                    </tr>
                  ))
                ) : filteredContracts.length === 0 ? (
                  <tr>
                    <td colSpan={8}>
                      <EmptyState onNew={openNew} hasFilter={!!search || !!filterStatus} />
                    </td>
                  </tr>
                ) : (
                  filteredContracts.map((c) => {
                    const displayStatus = resolveDisplayStatus(c);
                    const rowCls =
                      displayStatus === 'EXPIRING_SOON'
                        ? 'bg-amber-50/60'
                        : displayStatus === 'EXPIRED'
                        ? 'bg-red-50/40'
                        : displayStatus === 'TERMINATED'
                        ? 'bg-surface-container-lowest/80'
                        : '';
                    const isSelected = selectedContract?.id === c.id && panelMode === 'edit';
                    return (
                      <tr
                        key={c.id}
                        className={`${rowCls} ${isSelected ? 'ring-2 ring-inset ring-primary' : ''} cursor-pointer hover:bg-surface-container-lowest`}
                        onClick={() => openEdit(c)}
                      >
                        <td className="pl-4 font-semibold text-on-surface">
                          {c.roomNo}
                        </td>
                        <td>
                          <div className="font-medium text-on-surface">
                            {c.primaryTenant?.fullName ?? '—'}
                          </div>
                          {c.primaryTenant?.phone && (
                            <div className="text-[11px] text-on-surface-variant">{c.primaryTenant.phone}</div>
                          )}
                        </td>
                        <td className="text-on-surface">{fmtDate(c.startDate)}</td>
                        <td className="text-on-surface">
                          <span>{fmtDate(c.endDate)}</span>
                          {displayStatus === 'EXPIRING_SOON' && (
                            <span className="ml-1.5 text-[11px] font-semibold text-amber-600">
                              ({daysUntil(c.endDate)}d)
                            </span>
                          )}
                        </td>
                        <td className="font-medium text-on-surface">{fmtMoney(c.rentAmount)}</td>
                        <td className="text-on-surface">{fmtMoney(c.depositAmount)}</td>
                        <td>
                          <StatusBadge status={displayStatus} />
                        </td>
                        <td className="pr-4 text-right">
                          <button
                            className="inline-flex items-center gap-2 rounded-lg border border-outline bg-surface-container-lowest px-4 py-2 text-sm font-medium text-on-surface shadow-sm transition-colors hover:bg-surface-container flex items-center gap-1 text-xs"
                            onClick={(e) => {
                              e.stopPropagation();
                              openEdit(c);
                            }}
                          >
                            <Pencil size={11} />
                            แก้ไข
                          </button>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination footer */}
          {!loading && filteredContracts.length > 0 && (
            <div className="flex items-center justify-between border-t border-outline-variant px-4 py-2.5">
              <span className="text-xs text-on-surface-variant">
                แสดง {filteredContracts.length} จาก {total} สัญญา
              </span>
              <div className="flex items-center gap-1">
                <button
                  className="inline-flex items-center gap-2 rounded-lg border border-outline bg-surface-container-lowest px-4 py-2 text-sm font-medium text-on-surface shadow-sm transition-colors hover:bg-surface-container disabled:opacity-40 disabled:cursor-not-allowed"
                  disabled={page <= 1}
                  onClick={() => setPage((p) => Math.max(1, p - 1))}
                >
                  ก่อนหน้า
                </button>
                <span className="px-2 text-xs text-on-surface-variant">หน้า {page}</span>
                <button
                  className="inline-flex items-center gap-2 rounded-lg border border-outline bg-surface-container-lowest px-4 py-2 text-sm font-medium text-on-surface shadow-sm transition-colors hover:bg-surface-container disabled:opacity-40 disabled:cursor-not-allowed"
                  disabled={page >= Math.ceil(total / 50)}
                  onClick={() => setPage((p) => p + 1)}
                >
                  ถัดไป
                </button>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* ── Side Panel ───────────────────────────────────────────── */}
      {panelMode !== 'none' && (
        <aside className="fixed right-0 top-0 z-30 flex h-full w-full flex-col border-l border-outline-variant bg-surface-container-lowest shadow-2xl xl:w-[420px]">
          {/* Panel header */}
          <div className="flex items-center justify-between border-b border-outline-variant px-5 py-4">
            <div className="flex items-center gap-2">
              {panelMode === 'new' ? (
                <Plus size={16} className="text-primary" />
              ) : (
                <Pencil size={15} className="text-primary" />
              )}
              <span className="text-[15px] font-semibold text-on-surface">
                {panelMode === 'new' ? 'สัญญาใหม่' : `แก้ไข — ห้อง ${selectedContract?.roomNo}`}
              </span>
            </div>
            <button
              onClick={closePanel}
              className="flex h-7 w-7 items-center justify-center rounded-md text-on-surface-variant hover:bg-surface-container hover:text-on-surface"
            >
              <X size={15} />
            </button>
          </div>

          {/* Panel body */}
          <div className="flex-1 overflow-y-auto p-5">
            {panelMode === 'new' ? (
              <NewContractForm
                form={newForm}
                setForm={setNewForm}
                rooms={rooms}
                tenants={selectedTenants}
                tenantsLoading={tenantsLoading}
                onRoomChange={(roomNo) => {
                  setNewForm((f) => ({ ...f, roomId: roomNo, primaryTenantId: '' }));
                }}
                onSubmit={handleNewSubmit}
                saving={newSaving}
                error={newError}
                onCancel={closePanel}
              />
            ) : (
              <EditContractForm
                contract={selectedContract!}
                form={editForm}
                setForm={setEditForm}
                onSubmit={handleEditSubmit}
                saving={editSaving}
                error={editError}
                success={editSuccess}
                onCancel={closePanel}
              />
            )}
          </div>
        </aside>
      )}

      {/* Backdrop for panel on mobile */}
      {panelMode !== 'none' && (
        <div
          className="fixed inset-0 z-20 bg-black/20 xl:hidden"
          onClick={closePanel}
        />
      )}
    </div>
  );
}

// ─── New Contract Form ────────────────────────────────────────────────────────

function NewContractForm({
  form,
  setForm,
  rooms,
  tenants,
  tenantsLoading,
  onRoomChange,
  onSubmit,
  saving,
  error,
  onCancel,
}: {
  form: typeof EMPTY_NEW_FORM;
  setForm: React.Dispatch<React.SetStateAction<typeof EMPTY_NEW_FORM>>;
  rooms: RoomOption[];
  tenants: TenantOption[];
  tenantsLoading: boolean;
  onRoomChange: (roomNo: string) => void;
  onSubmit: (e: React.FormEvent) => void;
  saving: boolean;
  error: string | null;
  onCancel: () => void;
}) {
  const patch = (k: keyof typeof EMPTY_NEW_FORM, v: string) =>
    setForm((f) => ({ ...f, [k]: v }));

  return (
    <form onSubmit={onSubmit} className="flex flex-col gap-4">
      <p className="text-[12px] text-on-surface-variant leading-relaxed">
        สร้างสัญญาเช่าใหม่ ผู้เช่าที่เลือกต้องเป็น<strong>ผู้เช่าหลัก</strong>ของห้องที่เลือก
        และต้องไม่มีสัญญาใช้งานอยู่สำหรับห้องนั้น
      </p>

      {/* Room select */}
      <div>
        <label className="mb-1 block text-[12px] font-semibold text-on-surface">
          หมายเลขห้อง <span className="text-red-500">*</span>
        </label>
        <select
          className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20 w-full"
          required
          value={form.roomId}
          onChange={(e) => onRoomChange(e.target.value)}
        >
          <option value="">— เลือกห้อง —</option>
          {rooms.map((r) => (
            <option key={r.roomNo} value={r.roomNo}>
              {r.roomNo} (Floor {r.floorNo})
            </option>
          ))}
        </select>
      </div>

      {/* Tenant select */}
      <div>
        <label className="mb-1 block text-[12px] font-semibold text-on-surface">
          ผู้เช่าหลัก <span className="text-red-500">*</span>
        </label>
        {tenantsLoading ? (
          <div className="flex h-9 items-center rounded-md border border-outline-variant px-3 text-xs text-on-surface-variant animate-pulse">
            กำลังโหลดผู้เช่า…
          </div>
        ) : (
          <select
            className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20 w-full"
            required
            disabled={!form.roomId}
            value={form.primaryTenantId}
            onChange={(e) => patch('primaryTenantId', e.target.value)}
          >
            <option value="">— เลือกผู้เช่า —</option>
            {tenants.map((t) => (
              <option key={t.id} value={t.id}>
                {t.fullName} · {t.phone}
              </option>
            ))}
          </select>
        )}
        {form.roomId && !tenantsLoading && tenants.length === 0 && (
          <p className="mt-1 text-[11px] text-amber-600">
            ไม่พบผู้เช่าสำหรับห้องนี้ กรุณากำหนดผู้เช่าหลักก่อน
          </p>
        )}
      </div>

      {/* Date range */}
      <div className="grid grid-cols-2 gap-3">
        <div>
          <label className="mb-1 block text-[12px] font-semibold text-on-surface">
            วันที่เริ่ม <span className="text-red-500">*</span>
          </label>
          <input
            type="date"
            className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20 w-full"
            required
            value={form.startDate}
            onChange={(e) => patch('startDate', e.target.value)}
          />
        </div>
        <div>
          <label className="mb-1 block text-[12px] font-semibold text-on-surface">
            วันที่สิ้นสุด <span className="text-red-500">*</span>
          </label>
          <input
            type="date"
            className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20 w-full"
            required
            value={form.endDate}
            onChange={(e) => patch('endDate', e.target.value)}
          />
        </div>
      </div>

      {/* Rent & Deposit */}
      <div className="grid grid-cols-2 gap-3">
        <div>
          <label className="mb-1 block text-[12px] font-semibold text-on-surface">
            ค่าเช่ารายเดือน (฿) <span className="text-red-500">*</span>
          </label>
          <input
            type="number"
            min="1"
            max="999999"
            step="0.01"
            className="w-full rounded-xl border border-outline bg-surface-container-lowest px-3 py-2.5 text-sm text-on-surface focus:border-primary focus:outline-none focus:ring-2 focus:ring-primary/20 w-full"
            required
            placeholder="e.g. 8000"
            value={form.rentAmount}
            onChange={(e) => patch('rentAmount', e.target.value)}
          />
        </div>
        <div>
