  if (!pathname) return 'Apartment ERP';
  for (const { prefix, label } of PAGE_TITLES) {
    if (pathname === prefix || pathname.startsWith(prefix + '/')) {
      return label;
    }
  }
  return 'Apartment ERP';
}

